+/**
+ * Safely parse JSON with fallback.
+ */
+function safeJsonParse<T>(json: string, fallback: T): T {
+  try {
+    return JSON.parse(json) as T;
+  } catch {
+    logger.warn({ json: json.slice(0, 100) }, "Failed to parse JSON, using fallback");
+    return fallback;
+  }
+}
